#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) scanf("%d", &A[i]);
        for (int i = 0; i < N; i++) scanf("%d", &B[i]);
        int moves = 0;
        int S1[N][N] = {0}, S2[N][N] = {0};
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (B[j] > A[i] && gcd(A[i], B[j]) != 1) {
                    for (int p = 0; p < N; p++) {
                        for (int q = 0; q < N; q++) {
                            if (B[p] < A[q] && gcd(A[q], B[p]) != 1 && gcd(gcd(A[i], B[j]), gcd(A[q], B[p])) != 1 && !S1[i][j] && !S2[p][q]) {
                                moves++;
                                S1[i][j] = 1;
                                S2[p][q] = 1;
                            }
                        }
                    }
                }
            }
        }
        printf("%d\n", moves);
    }
    return 0;
}

