            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (B[j] > A[i] && gcd(A[i], B[j]) != 1) {
                        for (int p = 0; p < N; p++) {
                            for (int q = 0; q < N; q++) {
                                if (B[p] < A[q] && gcd(A[q], B[p]) != 1 && gcd(gcd(A[i], B[j]), gcd(A[q], B[p])) != 1 && !S1[i][j] && !S2[p][q]) {
